(7, 1, 'user', 'phim nào xem mà khóc sướt mướt', NULL, '2026-07-17 03:16:02', '2026-07-17 03:16:02'),
(8, 1, 'assistant', 'Nếu bạn muốn tìm những bộ phim cảm động, đong đầy nước mắt thì không thể bỏ qua Titanic - câu chuyện tình yêu kinh điển trên con tàu định mệnh, hoặc Hương Vị Tình Thân (Phần 1) với những thử thách gia đình đầy chạm cảm xúc. Cả hai phim đều hoàn toàn miễn phí trên gói Free của bạn đấy!', '{\"movies\":[{\"id\":2,\"title\":\"Titanic\",\"thumbnail\":\"\\/storage\\/data\\/img\\/titanic.jpg\",\"rating\":8.8,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/2\\/introduce\"},{\"id\":28,\"title\":\"H\\u01b0\\u01a1ng V\\u1ecb T\\u00ecnh Th\\u00e2n (Ph\\u1ea7n 1)\",\"thumbnail\":\"\\/storage\\/data\\/img\\/huong_vi_tinh_than_p1_img.jpg\",\"rating\":8.4,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/28\\/introduce\"}]}', '2026-07-17 03:16:04', '2026-07-17 03:16:04'),
(9, 1, 'user', 'Hôm nay xem gì?', NULL, '2026-07-18 15:15:37', '2026-07-18 15:15:37'),
