(11, 2, 'user', 'Phim mới nổi bật', NULL, '2026-07-19 14:23:02', '2026-07-19 14:23:02'),
(12, 2, 'assistant', 'Đây là những phim mới nổi bật trong kho CineHub, bạn xem thử nhé!', '{\"movies\":[{\"id\":194,\"title\":\"Nga\\u0300y x\\u01b0a co\\u0301 m\\u00f4\\u0323t chuy\\u00ea\\u0323n ti\\u0300nh\",\"thumbnail\":\"\\/storage\\/posters\\/6gO0EDANoBdXMazgvLW9bDDHl6H003zFNHZrjVc9.jpg\",\"rating\":0,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/194\\/introduce\"},{\"id\":148,\"title\":\"Planet Earth (2006)\",\"thumbnail\":\"\\/storage\\/posters\\/Kuos3oTaAjXcgk1NbcC2iU4xFRfAYFK5sYc3JsKQ.webp\",\"rating\":6.5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/148\\/introduce\"},{\"id\":163,\"title\":\"Saving Private Ryan (1998)\",\"thumbnail\":\"\\/storage\\/posters\\/bwcPK3Oz79JUM234VtUDu9rvL2Tv5QI2dW2bDoSI.webp\",\"rating\":6.5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/163\\/introduce\"},{\"id\":178,\"title\":\"Rocky (1976)\",\"thumbnail\":\"\\/storage\\/posters\\/CDNaX27D7ivhj2Wyu3wpYNIBmly2ehuPiFzDrvhQ.webp\",\"rating\":6.5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/178\\/introduce\"}]}', '2026-07-19 14:23:02', '2026-07-19 14:23:02'),
(13, 2, 'user', 'hello', NULL, '2026-07-19 14:33:48', '2026-07-19 14:33:48'),
(14, 2, 'assistant', 'Chào bạn! Mình là CineBot, trợ lý chọn phim của CineHub. Bạn đang tìm kiếm phim thuộc thể loại nào hôm nay? Mình có rất nhiều phim hành động, tình cảm, phiêu lưu và hoạt hình hấp dẫn sẵn sàng giới thiệu cho bạn đấy.', '{\"movies\":[]}', '2026-07-19 14:33:52', '2026-07-19 14:33:52'),
(15, 2, 'user', 'tôi đang ở gói nào và hay xem thể loại nào nhất', NULL, '2026-07-19 14:35:52', '2026-07-19 14:35:52'),
(16, 2, 'assistant', 'Bạn đang sử dụng gói Premium cao cấp nhất của CineHub. Qua lịch sử xem, bạn hay xem nhất các thể loại: Hành động, Tình cảm, Phiêu lưu và Hoạt hình. Dưới đây là một số phim cực đỉnh thuộc các thể loại này dành riêng cho bạn: Game of Thrones, Phàm Nhân Tu Tiên, Avengers: Endgame và Titanic.', '{\"movies\":[{\"id\":8,\"title\":\"Game of Thrones\",\"thumbnail\":\"\\/storage\\/data\\/img\\/game_of_thrones_img.webp\",\"rating\":9.3,\"level\":\"Premium\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/8\\/introduce\"},{\"id\":51,\"title\":\"Pha\\u0300m Nh\\u00e2n Tu Ti\\u00ean\",\"thumbnail\":\"\\/storage\\/posters\\/V7ZPSN3AoJ6aLu8oTLYttQJ3nW0IjOoR2iBmEaf9.jpg\",\"rating\":0,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/51\\/introduce\"},{\"id\":1,\"title\":\"Avengers: Endgame\",\"thumbnail\":\"\\/storage\\/data\\/img\\/avengers_end_game_img.jpg\",\"rating\":9.2,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/1\\/introduce\"},{\"id\":2,\"title\":\"Titanic\",\"thumbnail\":\"\\/storage\\/data\\/img\\/titanic.jpg\",\"rating\":8.8,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/2\\/introduce\"}]}', '2026-07-19 14:35:54', '2026-07-19 14:35:54'),
(17, 2, 'user', 'cho tôi vài bộ phim hành động đi', NULL, '2026-07-19 14:58:51', '2026-07-19 14:58:51'),
(18, 2, 'assistant', 'Chào bạn, với gói Premium, bạn có thể thưởng thức trọn vẹn những bộ phim hành động đặc sắc nhất. Dưới đây là những bộ phim hành động đỉnh cao dành cho bạn:', '{\"movies\":[{\"id\":9,\"title\":\"Breaking Bad\",\"thumbnail\":\"\\/storage\\/data\\/img\\/breaking_bad_img.jpg\",\"rating\":9.5,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/9\\/introduce\"},{\"id\":1,\"title\":\"Avengers: Endgame\",\"thumbnail\":\"\\/storage\\/data\\/img\\/avengers_end_game_img.jpg\",\"rating\":9.2,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/1\\/introduce\"},{\"id\":14,\"title\":\"Sherlock\",\"thumbnail\":\"\\/storage\\/data\\/img\\/Sherlock_img.jpg\",\"rating\":9.1,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/14\\/introduce\"},{\"id\":51,\"title\":\"Pha\\u0300m Nh\\u00e2n Tu Ti\\u00ean\",\"thumbnail\":\"\\/storage\\/posters\\/V7ZPSN3AoJ6aLu8oTLYttQJ3nW0IjOoR2iBmEaf9.jpg\",\"rating\":0,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/51\\/introduce\"}]}', '2026-07-19 14:58:53', '2026-07-19 14:58:53'),
(19, 2, 'user', 'hôm nay có bộ nào chữa lành hông', NULL, '2026-07-20 21:36:57', '2026-07-20 21:36:57'),
(20, 2, 'assistant', 'Gemini đang phản hồi chậm, nhưng CineBot đã chọn nhanh một vài phim phù hợp từ kho CineHub cho bạn:', '{\"movies\":[{\"id\":51,\"title\":\"Pha\\u0300m Nh\\u00e2n Tu Ti\\u00ean\",\"thumbnail\":\"\\/storage\\/posters\\/V7ZPSN3AoJ6aLu8oTLYttQJ3nW0IjOoR2iBmEaf9.jpg\",\"rating\":null,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/51\\/introduce\"},{\"id\":28,\"title\":\"H\\u01b0\\u01a1ng V\\u1ecb T\\u00ecnh Th\\u00e2n (Ph\\u1ea7n 1)\",\"thumbnail\":\"\\/storage\\/data\\/img\\/huong_vi_tinh_than_p1_img.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/28\\/introduce\"},{\"id\":33,\"title\":\"Phim ng\\u1eafn: 20 N\\u0103m 20 M\\u00f3n \\u0102n\",\"thumbnail\":\"\\/storage\\/data\\/img\\/20_nam.webp\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/33\\/introduce\"},{\"id\":37,\"title\":\"Phim ng\\u1eafn: Ng\\u00e3 Ba \\u0110\\u1ed3ng L\\u1ed9c\",\"thumbnail\":\"\\/storage\\/data\\/img\\/nga_ba_dong_loc_img.jpg\",\"rating\":null,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/37\\/introduce\"}]}', '2026-07-20 21:36:58', '2026-07-20 21:36:58'),
