(23, 2, 'user', 'hello', NULL, '2026-07-20 22:03:40', '2026-07-20 22:03:40'),
(24, 2, 'assistant', 'Xin chào! Mình là CineBot, trợ lý chọn phim của bạn. Hôm nay bạn có muốn thưởng thức những bộ phim thuộc thể loại yêu thích như Hành động, Tình cảm, Phiêu lưu hay Hoạt hình không? Dưới đây là một vài gợi ý tuyệt vời dành cho bạn.', '{\"movies\":[{\"id\":51,\"title\":\"Pha\\u0300m Nh\\u00e2n Tu Ti\\u00ean\",\"thumbnail\":\"\\/storage\\/posters\\/V7ZPSN3AoJ6aLu8oTLYttQJ3nW0IjOoR2iBmEaf9.jpg\",\"rating\":10,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/51\\/introduce\"},{\"id\":2,\"title\":\"Titanic\",\"thumbnail\":\"\\/storage\\/data\\/img\\/titanic.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/2\\/introduce\"},{\"id\":5,\"title\":\"Toy Story 4\",\"thumbnail\":\"\\/storage\\/data\\/img\\/toy_story_img.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/5\\/introduce\"},{\"id\":7,\"title\":\"Indiana Jones\",\"thumbnail\":\"\\/storage\\/data\\/img\\/indiana_jones_img.jpg\",\"rating\":4,\"level\":\"Gold\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/7\\/introduce\"}]}', '2026-07-20 22:03:59', '2026-07-20 22:03:59'),
(25, 2, 'user', 'hôm nay tôi buồn', NULL, '2026-07-21 02:13:41', '2026-07-21 02:13:41'),
(26, 2, 'assistant', 'Chia sẻ nỗi buồn cùng bạn nhé. Hãy để những bộ phim tình cảm nhẹ nhàng và hoạt hình vui vẻ này xoa dịu tâm trạng của bạn hôm nay. Với gói Premium, bạn có thể xem ngay lập tức.', '{\"movies\":[{\"id\":2,\"title\":\"Titanic\",\"thumbnail\":\"\\/storage\\/data\\/img\\/titanic.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/2\\/introduce\"},{\"id\":5,\"title\":\"Toy Story 4\",\"thumbnail\":\"\\/storage\\/data\\/img\\/toy_story_img.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/5\\/introduce\"},{\"id\":28,\"title\":\"H\\u01b0\\u01a1ng V\\u1ecb T\\u00ecnh Th\\u00e2n (Ph\\u1ea7n 1)\",\"thumbnail\":\"\\/storage\\/data\\/img\\/huong_vi_tinh_than_p1_img.jpg\",\"rating\":5,\"level\":\"Free\",\"url\":\"http:\\/\\/127.0.0.1:8000\\/movies\\/28\\/introduce\"}]}', '2026-07-21 02:13:55', '2026-07-21 02:13:55');
