INSERT INTO `theater_contracts` (`id`, `contract_code`, `theater_id`, `representative_user_id`, `super_admin_id`, `renewed_from_id`, `start_date`, `end_date`, `bestseller_price_min`, `bestseller_price_max`, `new_release_price_min`, `new_release_price_max`, `hot_movie_price_min`, `hot_movie_price_max`, `admin_permissions`, `auto_revoke_terms`, `party_terms`, `super_admin_signature`, `representative_signature`, `pdf_path`, `source_pdf_path`, `extracted_text`, `status`, `activated_at`, `revoked_at`, `created_at`, `updated_at`) VALUES
(1, 'BETA-TPHCM-2026', 8, 39, 2, NULL, '2026-08-01', '2026-12-31', 90000, 100000, 100000, 120000, 120000, 150000, '[\"Qu\\u1ea3n l\\u00fd th\\u00f4ng tin r\\u1ea1p \\u0111\\u01b0\\u1ee3c ph\\u00e2n quy\\u1ec1n\",\"Qu\\u1ea3n l\\u00fd ph\\u00f2ng chi\\u1ebfu v\\u00e0 s\\u01a1 \\u0111\\u1ed3 gh\\u1ebf\",\"Qu\\u1ea3n l\\u00fd l\\u1ecbch chi\\u1ebfu trong ph\\u1ea1m vi r\\u1ea1p\",\"Qu\\u1ea3n l\\u00fd nh\\u00e2n vi\\u00ean qu\\u1ea7y c\\u1ee7a r\\u1ea1p\",\"Qu\\u1ea3n l\\u00fd combo, \\u0111\\u1ed3 \\u0103n v\\u00e0 b\\u00e1o c\\u00e1o v\\u1eadn h\\u00e0nh r\\u1ea1p\",\"H\\u1ed7 tr\\u1ee3 ki\\u1ec3m tra v\\u00e9 v\\u00e0 nghi\\u1ec7p v\\u1ee5 b\\u00e1n v\\u00e9 t\\u1ea1i r\\u1ea1p\"]', 'Khi hợp đồng hết hiệu lực, hệ thống CineHub tự động thu hồi quyền Admin rạp của Đại diện rạp và chuyển tài khoản về Người dùng nếu Super Admin chưa gia hạn hợp đồng mới còn hiệu lực.', NULL, 'CineHub', 'Beta TPHCM', 'contracts/BETA-TPHCM-2026.pdf', NULL, 'Bên A (Rạp chiếu phim): Beta TPHCM\nBên B: CineHub\nBắt đầu: 01/08/2026\nKết thúc: 31/12/2026\nGia hạn: thêm 06 tháng nếu hai bên đồng ý bằng văn bản.', 'pending', NULL, NULL, '2026-07-12 12:32:26', '2026-07-12 12:32:33'),
(2, 'CH-RAP-01-2026', 1, 17, 2, NULL, '2026-01-01', '2026-12-31', 90000, 100000, 100000, 120000, 120000, 150000, '[\"Qu\\u1ea3n l\\u00fd th\\u00f4ng tin r\\u1ea1p \\u0111\\u01b0\\u1ee3c ph\\u00e2n quy\\u1ec1n\",\"Qu\\u1ea3n l\\u00fd ph\\u00f2ng chi\\u1ebfu v\\u00e0 s\\u01a1 \\u0111\\u1ed3 gh\\u1ebf\",\"Qu\\u1ea3n l\\u00fd l\\u1ecbch chi\\u1ebfu trong ph\\u1ea1m vi r\\u1ea1p\",\"Qu\\u1ea3n l\\u00fd nh\\u00e2n vi\\u00ean qu\\u1ea7y c\\u1ee7a r\\u1ea1p\",\"Qu\\u1ea3n l\\u00fd combo, \\u0111\\u1ed3 \\u0103n v\\u00e0 b\\u00e1o c\\u00e1o v\\u1eadn h\\u00e0nh r\\u1ea1p\",\"H\\u1ed7 tr\\u1ee3 ki\\u1ec3m tra v\\u00e9 v\\u00e0 nghi\\u1ec7p v\\u1ee5 b\\u00e1n v\\u00e9 t\\u1ea1i r\\u1ea1p\"]', 'Khi hợp đồng hết hiệu lực, hệ thống CineHub tự động thu hồi quyền Admin rạp của Đại diện rạp và chuyển tài khoản về Người dùng nếu Super Admin chưa gia hạn hợp đồng mới còn hiệu lực.', NULL, 'CineHub', 'Admin Rạp CGV Vincom', 'contracts/CH-RAP-01-2026.pdf', NULL, NULL, 'active', NULL, NULL, '2026-07-12 12:42:14', '2026-07-12 12:42:14'),
